import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { loginUser } from '../services/api';
import { useAuth } from '../context/AuthContext';

export default function LoginPage() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const [loginType, setLoginType] = useState('employee');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await loginUser(form);
      if (loginType === 'admin' && data.role !== 'admin') {
        toast.error('You are not an admin!');
        setLoading(false);
        return;
      }
      if (loginType === 'employee' && data.role !== 'employee') {
        toast.error('You are not an employee! Use Admin Login.');
        setLoading(false);
        return;
      }
      login(data);
      toast.success(`Welcome back, ${data.name}!`);
      navigate(data.role === 'admin' ? '/admin' : '/employee');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-darkbg relative overflow-hidden flex items-center justify-center p-4">
      {/* Aesthetic Background Blobs */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-brand-600/30 rounded-full mix-blend-screen filter blur-[100px] animate-blob"></div>
      <div className="absolute top-[20%] right-[-10%] w-96 h-96 bg-accent-500/20 rounded-full mix-blend-screen filter blur-[100px] animate-blob" style={{ animationDelay: '2s' }}></div>
      <div className="absolute -bottom-32 left-[20%] w-96 h-96 bg-brand-400/20 rounded-full mix-blend-screen filter blur-[100px] animate-blob" style={{ animationDelay: '4s' }}></div>

      <div className="w-full max-w-md relative z-10">
        <div className="text-center mb-10">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-gradient-to-tr from-brand-600 to-accent-500 shadow-lg shadow-brand-500/30 mb-5">
            <span className="text-3xl">⚡</span>
          </div>
          <h1 className="font-display font-bold text-white text-4xl tracking-tight text-glow">TaskFlow</h1>
          <p className="text-gray-400 mt-2">Sign in to your account</p>
        </div>

        <div className="glass-card rounded-3xl p-8 shadow-2xl shadow-black/50">
          {/* Dual Login Toggle */}
          <div className="flex p-1 bg-white/5 rounded-xl mb-6 border border-white/10">
            <button 
              onClick={() => setLoginType('employee')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${loginType === 'employee' ? 'bg-brand-600 shadow-lg text-white' : 'text-gray-400 hover:text-gray-200'}`}>
              Employee Login
            </button>
            <button 
              onClick={() => setLoginType('admin')}
              className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${loginType === 'admin' ? 'bg-brand-600 shadow-lg text-white' : 'text-gray-400 hover:text-gray-200'}`}>
              Admin Login
            </button>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">{loginType === 'admin' ? 'Admin Email' : 'Employee Email'}</label>
              <input type="email" required value={form.email} onChange={e => setForm({ ...form, email: e.target.value })}
                className="w-full px-5 py-3.5 glass rounded-xl text-white placeholder-gray-500 focus:outline-none focus:border-brand-400 focus:ring-2 focus:ring-brand-500/50 transition-all"
                placeholder={loginType === 'admin' ? "admin@taskmanager.com" : "you@example.com"} />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Password</label>
              <input type="password" required value={form.password} onChange={e => setForm({ ...form, password: e.target.value })}
                className="w-full px-5 py-3.5 glass rounded-xl text-white placeholder-gray-500 focus:outline-none focus:border-brand-400 focus:ring-2 focus:ring-brand-500/50 transition-all"
                placeholder="••••••••" />
            </div>
            <button type="submit" disabled={loading}
              className="w-full py-3.5 bg-gradient-to-r from-brand-600 to-accent-500 hover:from-brand-500 hover:to-accent-400 text-white font-semibold rounded-xl shadow-lg shadow-brand-500/25 transition-all transform hover:-translate-y-0.5 disabled:opacity-50 disabled:transform-none mt-4">
              {loading ? 'Signing in...' : `Sign In as ${loginType === 'admin' ? 'Admin' : 'Employee'}`}
            </button>
          </form>

          {loginType === 'employee' && (
            <div className="mt-6 text-center text-sm text-gray-400">
              Don't have an account?{' '}
              <Link to="/register" className="text-brand-400 hover:text-brand-300 font-semibold transition-colors">Create one now</Link>
            </div>
          )}

          {loginType === 'admin' && (
            <div className="mt-8 p-4 bg-brand-900/20 rounded-2xl border border-brand-500/20 backdrop-blur-md">
              <p className="text-xs text-brand-300 font-semibold mb-2 uppercase tracking-wider">Demo Admin Credentials</p>
              <p className="text-xs text-gray-400 font-mono">Email: admin@taskmanager.com</p>
              <p className="text-xs text-gray-400 font-mono mt-1">Password: admin123</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
